import heapq

def solve(m: int, n: int, waitCost: list[list[int]]) -> int:
    # Directions: right (0, 1) and down (1, 0)
    directions = [(0, 1), (1, 0)]

    # Priority queue: (total_cost, i, j, step_mod)
    heap = []
    # Initial state: (cost=1, i=0, j=0, step_mod=1) because first step is odd (1)
    heapq.heappush(heap, (1, 0, 0, 1))

    # Visited dictionary: key is (i, j, step_mod), value is the minimal cost
    visited = {}
    visited[(0, 0, 1)] = 1

    while heap:
        current_cost, i, j, step_mod = heapq.heappop(heap)

        # Check if reached the destination
        if i == m - 1 and j == n - 1:
            return current_cost

        # If current state's cost is higher than recorded, skip
        if visited.get((i, j, step_mod), float('inf')) < current_cost:
            continue

        if step_mod == 1:
            # Odd step: move right or down
            for di, dj in directions:
                ni, nj = i + di, j + dj
                if 0 <= ni < m and 0 <= nj < n:
                    new_cost = current_cost + (ni + 1) * (nj + 1)
                    new_step_mod = 0  # next step is even
                    if (ni, nj, new_step_mod) not in visited or new_cost < visited.get((ni, nj, new_step_mod), float('inf')):
                        visited[(ni, nj, new_step_mod)] = new_cost
                        heapq.heappush(heap, (new_cost, ni, nj, new_step_mod))
        else:
            # Even step: wait
            new_cost = current_cost + waitCost[i][j]
            new_step_mod = 1  # next step is odd
            if (i, j, new_step_mod) not in visited or new_cost < visited.get((i, j, new_step_mod), float('inf')):
                visited[(i, j, new_step_mod)] = new_cost
                heapq.heappush(heap, (new_cost, i, j, new_step_mod))

    return -1  # in case no path found (shouldn't happen as per problem constraints)
